insert into public.products
  (slug, name, tagline, description, category, material, price, dimensions, features, images)
select s.slug, s.name, s.tagline, s.description, s.category, s.material, s.price, s.dimensions, s.features, s.images
from seed s
where not exists (
  select 1 from public.deleted_product_slugs t where t.slug = s.slug
)
on conflict (slug) do nothing;
